公司Company类派生出集团公司Group类，扩展数据成员子公司数量
【问题描述】
        公司Company类包含公司名称name（字符串）、count人数（大于0的整数）两个数据成员和构造函数及成员函数show（显示公司信息）；由Company类派生出集团公司Group类，扩展数据成员子公司数量（大于0的整数）和构造函数及成员函数show（显示集团公司信息）。依次输入集团公司名name、子公司数量、总人数count，输出相应的集团公司信息。
        参考主函数：        
        int main()
        {
        string name;
        int count, total;
        cout << "请输入总公司名和子公司数量及总人数:";
        cin >> name >> total >> count;
        Group grp(name, count, total);
        grp.show();
        return 0;
        }
【输入形式】
【输出形式】
【样例输入】
请输入总公司名和子公司数量及总人数:信科集团 5 500
【样例输出】

信科集团
500
5
【样例输入】
请输入总公司名和子公司数量及总人数:信科集团 0 500
【样例输出】

子公司数量错误！
【样例输入】
请输入总公司名和子公司数量及总人数:信科集团 500 0
【样例输出】

人数错误！

#include <iostream>
#include <string>
using namespace std;

class Company {
protected:
    string name;
    int count;
public:
    Company(string n, int c) : name(n), count(c) {}
    virtual void show() {
        cout << name << endl << count << endl;
    }
};

class Group : public Company {
private:
    int total;
public:
    Group(string n, int c, int t) : Company(n, c), total(t) {
        if (c <= 0)
            cout << "子公司数量错误！" << endl;
        if (t <= 0)
            cout << "人数错误！" << endl;
    }
    void show() override {
        cout << name << endl << total << endl << count << endl;
    }
};

int main() {
    string name;
    int count, total;
    cout << "请输入总公司名和子公司数量及总人数:";
    cin >> name >> total >> count;
    Group grp(name, count, total);
    grp.show();
    return 0;
}

